DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'crm_partner_status') THEN CREATE TYPE public.crm_partner_status AS ENUM ('pending','active','suspended','terminated'); END IF; IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'crm_partner_tier') THEN CREATE TYPE public.crm_partner_tier AS ENUM ('standard','silver','gold','platinum'); END IF; IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'crm_payout_type') THEN CREATE TYPE public.crm_payout_type AS ENUM ('fixed_fee','percentage_of_first_year','percentage_of_first_invoice','account_credit'); END IF; IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'crm_signup_status') THEN CREATE TYPE public.crm_signup_status AS ENUM ('pending','trial','active_paid','churned','duplicate','rejected'); END IF; IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'crm_credit_transaction_type') THEN CREATE TYPE public.crm_credit_transaction_type AS ENUM ('credit_earned','credit_redeemed','credit_expired','adjustment'); END IF; IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'crm_flag_reason') THEN CREATE TYPE public.crm_flag_reason AS ENUM ('duplicate_company','self_referral','suspicious_velocity','fraudulent_company','chargeback','other'); END IF; END $$;